import{c as t,S as a,j as l,m as d}from"./chunks/framework.DvQr6YbT.js";const g=JSON.parse('{"title":"使用指南","description":"","frontmatter":{},"headers":[],"relativePath":"zh/guides/index.md","filePath":"zh/guides/index.md","lastUpdated":1783065655000}'),r={name:"zh/guides/index.md"};function o(i,e,n,s,c,h){return a(),l("div",null,[...e[0]||(e[0]=[d('<h1 id="使用指南" tabindex="-1">使用指南 <a class="header-anchor" href="#使用指南" aria-label="Permalink to “使用指南”">​</a></h1><p>这些指南覆盖 Knowlery 的日常工作流。</p><h2 id="初始化-vault" tabindex="-1">初始化 Vault <a class="header-anchor" href="#初始化-vault" aria-label="Permalink to “初始化 Vault”">​</a></h2><ol><li>打开 command palette。</li><li>运行 <strong>Knowlery: Initialize vault</strong>。</li><li>选择 Claude Code 或 OpenCode。</li><li>Review Knowlery 将创建的文件、skills 和配置。</li><li>可选地选择缺失工具的准备步骤。</li><li>运行 setup。</li><li>Setup 完成后打开 dashboard。</li></ol><p>如果你还在评估 Knowlery，建议先使用 test vault。Setup 会写入多个顶层文件和文件夹。</p><h2 id="阅读-dashboard" tabindex="-1">阅读 Dashboard <a class="header-anchor" href="#阅读-dashboard" aria-label="Permalink to “阅读 Dashboard”">​</a></h2><p>Knowlery 现在围绕一个行动优先的 dashboard 组织：</p><table tabindex="0"><thead><tr><th>区块</th><th>作用</th></tr></thead><tbody><tr><td>Today&#39;s move</td><td>从当前活动状态开始，选择一个小的下一步</td></tr><tr><td>Suggested moves</td><td>复制或发送 Process new material、Connect related notes、Challenge an idea、Fix note metadata、Draft an output 等可复用 prompts</td></tr><tr><td>Knowledge health</td><td>有 suggestions 等待处理时打开 Freshness Review</td></tr><tr><td>This note</td><td>review 当前 Markdown 笔记并寻找关联上下文</td></tr><tr><td>Recent activity</td><td>查看最近的私有 activity receipts</td></tr><tr><td>This week</td><td>生成 weekly summary，或发送 polish request</td></tr><tr><td>Bundles</td><td>分享一个 review 过的 knowledge bundle，或安装别人分享的 bundle</td></tr></tbody></table><p>最近活动或 vault 变化后，可以点刷新按钮。较长的 moves 和 activity 列表可以通过 <strong>View all</strong> 打开。</p><h2 id="使用-today-s-move" tabindex="-1">使用 Today&#39;s Move <a class="header-anchor" href="#使用-today-s-move" aria-label="Permalink to “使用 Today&#39;s Move”">​</a></h2><p>Today&#39;s move 是最直接的“现在发生了什么”视图。</p><ol><li>打开 dashboard。</li><li>阅读当前 summary 和高亮的下一步。</li><li>需要 agent prompt 时，使用复制或发送动作。</li><li>想记录自己对工作的简短想法时，使用 Add reflection。</li></ol><p>如果已有 activity receipts，Knowlery 会显示活跃 thread 和建议的下一步；如果没有，它会把你引向第一个 cook 或一个小的 setup 步骤。</p><h2 id="review-一篇笔记" tabindex="-1">Review 一篇笔记 <a class="header-anchor" href="#review-一篇笔记" aria-label="Permalink to “Review 一篇笔记”">​</a></h2><p>打开一篇 Markdown 笔记，然后查看 dashboard 中的 This note 区块。</p><p>Knowlery 会尝试识别当前笔记，把它和最近的知识活动关联起来，并准备一个聚焦的 prompt。适合把单篇笔记连接到旧材料、comparison 或可复用结构。</p><h2 id="生成-weekly-summary" tabindex="-1">生成 Weekly Summary <a class="header-anchor" href="#生成-weekly-summary" aria-label="Permalink to “生成 Weekly Summary”">​</a></h2><p>在需要更宏观的总结时，使用 This week 区块。</p><ol><li>使用 <strong>Generate summary</strong> 在 <code>.knowlery/reports/latest.html</code> 生成本地 HTML 报告。</li><li>使用 <strong>Open last report</strong> 在 Obsidian 外打开这个文件。</li><li>使用 <strong>Send for review</strong> 让 companion agent 写一版更精炼的 review summary。</li><li>使用 <strong>Check result</strong> 刷新 request/result 状态。</li></ol><p>报告还会保存一个带日期的 snapshot 到 <code>.knowlery/reports/weekly/</code>。</p><h2 id="使用-suggested-moves" tabindex="-1">使用 Suggested Moves <a class="header-anchor" href="#使用-suggested-moves" aria-label="Permalink to “使用 Suggested Moves”">​</a></h2><p>Suggested moves 让你从产品语言动作开始，而不是从原始 skill 名称开始。</p><p>Move catalog 包括：</p><table tabindex="0"><thead><tr><th>Move</th><th>用途</th></tr></thead><tbody><tr><td>Process new material</td><td>将粗糙笔记、摘录或对话整理成持久知识页面</td></tr><tr><td>Connect related notes</td><td>寻找旧笔记、相邻主题和可复用模式</td></tr><tr><td>Challenge an idea</td><td>检查假设、缺失证据、反例和风险</td></tr><tr><td>Fix note metadata</td><td>Review drift、重复、frontmatter gaps、broken links 和 index hygiene</td></tr><tr><td>Draft an output</td><td>把成熟主题转成 checklist、outline、template、proposal 或 decision memo</td></tr></tbody></table><p>打开某个 move 后，可以复制 prompt 或发送给配置好的 agent chat。打开 <strong>Settings -&gt; Knowlery -&gt; Skills</strong> 后，可以查看、创建、fork、编辑、禁用或删除底层 skills。</p><h3 id="推荐-skill-使用流" tabindex="-1">推荐 Skill 使用流 <a class="header-anchor" href="#推荐-skill-使用流" aria-label="Permalink to “推荐 Skill 使用流”">​</a></h3><table tabindex="0"><thead><tr><th>目标</th><th>Skill</th></tr></thead><tbody><tr><td>处理原始笔记</td><td><code>cook</code></td></tr><tr><td>询问 vault 已经知道什么</td><td><code>ask</code></td></tr><tr><td>寻找主题之间的桥梁</td><td><code>explore</code></td></tr><tr><td>审查假设</td><td><code>challenge</code></td></tr><tr><td>生成综合想法</td><td><code>ideas</code></td></tr><tr><td>检查结构问题</td><td><code>audit</code></td></tr><tr><td>清理组织结构</td><td><code>organize</code></td></tr></tbody></table><h2 id="分享-knowledge-bundle" tabindex="-1">分享 Knowledge Bundle <a class="header-anchor" href="#分享-knowledge-bundle" aria-label="Permalink to “分享 Knowledge Bundle”">​</a></h2><p>当你想把一部分 review 过的知识分享给别人时，使用 <strong>Share knowledge bundle</strong>（command palette 或 dashboard 的 Bundles 区块）。</p><ol><li>选择一个 seed 主题。Knowlery 会收集与它相连的知识页面和被引用的原始笔记（graph-closure）。</li><li>逐条 review 范围内的每一项。每个页面和原始笔记都处于 unreviewed / approved / flagged 三种状态之一——没有被 approve 的内容不会被导出。</li><li>查看自动 risk scan。它会在导出前高亮 emails、敏感 URLs、person pages 和会议类笔记。</li><li>确认 bundle 元数据（id、title、version、creator、license）和选项。</li><li>导出。Bundle 会写入 <code>.knowlery/exports/</code>，并可以保存为 <code>.zip</code> 用于分享。</li></ol><p>导出的 bundle 包含 approve 过的页面、用于导航的 <code>index.md</code> 和 <code>agent-index.json</code>、<code>_sources/</code> 下 approve 过的原始笔记、update log，以及给接收者的 README。如果开启了 &quot;Include SCHEMA.md&quot;，随包的 schema 只包含导出页面实际用到的 tags 和 domains——绝不会是整个 vault 的 taxonomy。</p><p>每个主题都有自己独立保存的 review scope，处理一个 bundle 不会影响另一个。</p><h2 id="安装-knowledge-bundle" tabindex="-1">安装 Knowledge Bundle <a class="header-anchor" href="#安装-knowledge-bundle" aria-label="Permalink to “安装 Knowledge Bundle”">​</a></h2><p>使用 <strong>Install knowledge bundle</strong>（command palette 或 dashboard 卡片）安装别人分享给你的 bundle。</p><ol><li>选择 bundle 的 <code>.zip</code> 或文件夹。</li><li>在写入任何内容之前，先 review manifest 和 conformance 预览。</li><li>安装。Bundle 会落到 <code>Library/&lt;bundle-id&gt;/</code>，并登记到 <code>.knowlery/bundles.json</code>。</li></ol><p>已安装的 bundles 会显示在 dashboard 上，也可以从那里卸载。安装会在 <code>KNOWLEDGE.md</code> 中加入检索指引，<code>/ask</code> skill 在回答问题时会显式检查已安装的 bundles。更新要求更高的 bundle 版本号；带 conformance 错误的 bundle 需要显式确认才能安装。</p><p>想把某个 bundle 页面变成自己的知识时，在 bundle concept 页面的 file menu 中使用 <strong>Fork to my knowledge</strong>——它会把页面复制到你自己的知识目录中。</p><h2 id="添加或编辑-rules" tabindex="-1">添加或编辑 Rules <a class="header-anchor" href="#添加或编辑-rules" aria-label="Permalink to “添加或编辑 Rules”">​</a></h2><p>Rules 用来指导 agent 在这个 vault 中如何行动。</p><ol><li>打开 <strong>Settings -&gt; Knowlery</strong>。</li><li>使用 <strong>Add rule</strong> 创建新 rule。</li><li>给 rule 一个聚焦的 filename 和 title。</li><li>用普通 markdown 编写指令。</li><li>保存并确认它出现在 rules list 中。</li></ol><p>好的 rule 应该短而可执行。相比一篇泛泛的写作风格说明，<code>Always cite source notes using wikilinks</code> 这样的指令更有效。</p><h2 id="切换平台" tabindex="-1">切换平台 <a class="header-anchor" href="#切换平台" aria-label="Permalink to “切换平台”">​</a></h2><p>可以在 settings tab 中切换 Claude Code 和 OpenCode。</p><p>Knowlery 会：</p><ul><li>创建目标 rules directory。</li><li>将旧平台目录中的 markdown rules 复制到新目录。</li><li>重新生成平台配置文件。</li><li>可选地清理旧平台配置。</li></ul><p>切换平台后建议 review 生成的 config，尤其是你有 custom rules 的时候。</p><h2 id="运行健康诊断" tabindex="-1">运行健康诊断 <a class="header-anchor" href="#运行健康诊断" aria-label="Permalink to “运行健康诊断”">​</a></h2><p>打开 <strong>Settings -&gt; Knowlery</strong>，在 Diagnostics 区块点击 <strong>Run diagnosis</strong>。</p><p>Knowlery 会检查：</p><ul><li>没有 incoming wikilinks 的孤立笔记。</li><li>无法解析到现有文件的损坏 wikilinks。</li><li><code>entities/</code>、<code>concepts/</code>、<code>comparisons/</code>、<code>queries/</code> 中缺失的 frontmatter。</li></ul><p>Health output 是建议性质。对真实 vault 做结构调整前，请先 review 诊断结果。</p><h2 id="运行-freshness-review" tabindex="-1">运行 Freshness Review <a class="header-anchor" href="#运行-freshness-review" aria-label="Permalink to “运行 Freshness Review”">​</a></h2><p>当你想让 agent 检查 compiled knowledge pages 是否过期或被新材料取代时，可以使用 Freshness Review。</p><ol><li>从 dashboard 打开 Knowledge health。</li><li>使用 <strong>Prepare request</strong> 在 <code>.knowlery/freshness/requests/</code> 下写入 request JSON。</li><li>复制 prompt，并单独运行 agent。</li><li>按 request 要求放好 result JSON，然后使用 <strong>Import results</strong>。</li><li>在应用、dismiss 或标记 incorrect 前，逐条 review suggestion。</li></ol><p>Knowlery 只会在你批准后 patch scalar freshness frontmatter。这个流程不会直接调用 model API。</p><h2 id="记录-reflection" tabindex="-1">记录 Reflection <a class="header-anchor" href="#记录-reflection" aria-label="Permalink to “记录 Reflection”">​</a></h2><p>在 command palette 或 dashboard 中使用 <strong>Add reflection</strong>，可以把一次 agent 会话或人工 review 的简短总结写进 Activity Ledger。</p><p>它会进入 Activity Ledger，而不是普通 vault note。</p><h2 id="重新生成-agent-config" tabindex="-1">重新生成 Agent Config <a class="header-anchor" href="#重新生成-agent-config" aria-label="Permalink to “重新生成 Agent Config”">​</a></h2><p>如果 agent instructions 漂移，或者 config file 被误改，可以在 settings tab 中重新生成平台配置。</p><p>这在修改 knowledge base name、切换平台、修复部分初始化失败的 vault 时很有用。</p><h2 id="安全地和-agents-一起工作" tabindex="-1">安全地和 Agents 一起工作 <a class="header-anchor" href="#安全地和-agents-一起工作" aria-label="Permalink to “安全地和 Agents 一起工作”">​</a></h2><p>让 agent 在 Knowlery vault 中工作时，建议：</p><ul><li>要求 agent 先阅读 <code>KNOWLEDGE.md</code>。</li><li>将 source notes 与 compiled knowledge pages 分开。</li><li>要求回答时使用 <code>[[wikilinks]]</code> 引用来源。</li><li>在依赖生成内容前 review 知识页面。</li><li>在大规模导入、迁移或 agent-generated changes 后运行 Health。</li></ul>',64)])])}const u=t(r,[["render",o]]);export{g as __pageData,u as default};
